1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	
15	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const basePremiumForItem = (item: Item): number =>
25	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
26	
27	const isNewcomer = (customer: Customer): boolean =>
28	  customer.yearsWithMHPCO === 0;
29	
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
32	
33	const surcharge = (base: number, applies: boolean, rate: number): number =>
34	  applies ? base * rate : 0;
35	
36	const premiumForItem = (item: Item, customer: Customer): number => {
37	  const base = basePremiumForItem(item);
38	  return (
39	    base +
40	    surcharge(base, item.cursed === true, CURSED_SURCHARGE_RATE) +
41	    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE) +
42	    surcharge(base, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
43	  );
44	};
45	
46	export const quote = (input: QuoteInput): { premium: number } => {
47	  const itemsTotal = input.items.reduce(
48	    (sum, item) => sum + premiumForItem(item, input.customer),
49	    0,
50	  );
51	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
52	};
53	
54	export const claim = (_input: unknown): unknown => {
55	  return undefined;
56	};
